package stats_test

import (
	"math"
	"testing"

	"github.com/montanaflynn/stats"
)

func TestSumEquivalence(t *testing.T) {
	// Test cases for Sum function
	testCases := []struct {
		name     string
		input    []float64
		expected float64
		hasError bool
	}{
		{"Empty slice", []float64{}, 0, true},
		{"Single value", []float64{5.0}, 5.0, false},
		{"Positive values", []float64{1.0, 2.0, 3.0, 4.0}, 10.0, false},
		{"Negative values", []float64{-1.0, -2.0, -3.0, -4.0}, -10.0, false},
		{"Mixed values", []float64{-10.5, 5.5, 1.5, 3.5}, 0.0, false},
		{"Zero values", []float64{0.0, 0.0, 0.0}, 0.0, false},
		{"Large values", []float64{1e10, 2e10, 3e10}, 6e10, false},
		{"Small values", []float64{1e-10, 2e-10, 3e-10}, 6e-10, false},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			// Create Float64Data from the slice
			data := stats.Float64Data(tc.input)

			// Call Sum
			result, err := stats.Sum(data)

			// Check error condition
			if tc.hasError {
				if err == nil {
					t.Errorf("Expected error for input %v but got none", tc.input)
				}
				if err != stats.EmptyInputErr {
					t.Errorf("Expected EmptyInputErr for input %v but got %v", tc.input, err)
				}
				if !math.IsNaN(result) {
					t.Errorf("Expected NaN for empty input but got %v", result)
				}
				return
			}

			// Check non-error case
			if err != nil {
				t.Errorf("Unexpected error for input %v: %v", tc.input, err)
			}

			// Check result with appropriate epsilon for floating point comparison
			if math.Abs(result-tc.expected) > 1e-10 {
				t.Errorf("For input %v, expected %v but got %v", tc.input, tc.expected, result)
			}
		})
	}
}

