use crate::careful::*;use serde::{Deserialize, Serialize};use serde_with::serde_as;use arbitrary::Arbitrary;use anyhow::Context;use anyhow::Error;use anyhow::Result;use anyhow::anyhow;
use crate::data::Float64Data;
use crate::legacy::EMPTY_INPUT_ERR;
use crate::sum::sum;

#[cfg(test)]
pub mod tests {
    use super::*;

    #[test]
    fn test_sum_equivalence() {
        // Test cases
        let test_cases = [
            ("Empty slice", vec![], true, 0.0),
            ("Single value", vec![5.0], false, 5.0),
            ("Positive values", vec![1.0, 2.0, 3.0, 4.0], false, 10.0),
            ("Negative values", vec![-1.0, -2.0, -3.0, -4.0], false, -10.0),
            ("Mixed values", vec![-10.5, 5.5, 1.5, 3.5], false, 0.0),
            ("Zero values", vec![0.0, 0.0, 0.0], false, 0.0),
            ("Large values", vec![1e10, 2e10, 3e10], false, 6e10),
            ("Small values", vec![1e-10, 2e-10, 3e-10], false, 6e-10),
        ];

        for (name, values, should_error, expected) in test_cases {
            let data = Float64Data(values);

            let result = sum(data);

            if should_error {
                // Should return an error for empty input
                assert!(result.is_err(), "{}: Expected error but got Ok", name);
                if let Err(err) = result {
                    assert!(
                        err.to_string().contains(&EMPTY_INPUT_ERR.err),
                        "{}: Expected empty input error but got: {}",
                        name,
                        err
                    );
                }
            } else {
                // Should return a valid result
                match result {
                    Ok(value) => {
                        assert!(
                            (value - expected).abs() < 1e-10,
                            "{}: Expected {} but got {}",
                            name,
                            expected,
                            value
                        );
                    }
                    Err(e) => {
                        panic!("{}: Unexpected error: {}", name, e);
                    }
                }
            }
        }
    }
}

