package stats_test

import (
	"reflect"
	"testing"

	"github.com/montanaflynn/stats"
)

func TestFloat64DataSum(t *testing.T) {
	for _, c := range []struct {
		in  []float64
		out float64
	}{
		{[]float64{1, 2, 3}, 6},
		{[]float64{1.0, 1.1, 1.2, 2.2}, 5.5},
		{[]float64{1, -1, 2, -3}, -1},
	} {
		// Create Float64Data from the slice
		data := stats.Float64Data(c.in)

		// Test the Sum method
		got, err := data.Sum()
		if err != nil {
			t.Errorf("Float64Data(%v).Sum() returned an error: %v", c.in, err)
		}
		if !reflect.DeepEqual(c.out, got) {
			t.Errorf("Float64Data(%v).Sum() => %v, want %v", c.in, got, c.out)
		}
	}

	// Test with empty slice
	data := stats.Float64Data{}
	_, err := data.Sum()
	if err == nil {
		t.Errorf("Float64Data{}.Sum() should have returned an error for empty slice")
	}
}

