	// Test cases
	testCases := []struct {
		name     string
		input    []float64
		expected float64
		hasError bool
	}{
		{"Basic case", []float64{1, 2, 3, 4, 5}, 3.0, false},
		{"Negative numbers", []float64{-10, -5, 0, 5, 10}, 0.0, false},
