		{"Empty slice", []float64{}, math.NaN(), true},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			result, err := Mean(tc.input)

			// Check error condition
			if tc.hasError && err == nil {
				t.Errorf("Expected error for input %v but got none", tc.input)
				return
			}

			if !tc.hasError && err != nil {
				t.Errorf("Unexpected error for input %v: %v", tc.input, err)
				return
			}

			// Skip comparison for error cases
			if tc.hasError {
				return
			}

			// For floating point comparison, use epsilon for approximate equality
			epsilon := 0.0000001
			if math.Abs(result-tc.expected) > epsilon {
				t.Errorf("Mean(%v) = %v, want %v", tc.input, result, tc.expected)
			}
		})
	}
}

