        let value = result.unwrap();
        let diff = (value - 0.2).abs();
        assert!(diff < epsilon, "Expected 0.2, got {}", value);
    }

    #[test]
    fn test_mean_empty_slice() {
        let input = Float64Data(vec![]);
        let result = mean(input);
        assert!(result.is_err());
    }
}

