package stats_test

import (
	"testing"

	"github.com/montanaflynn/stats"
)

func TestAutoCorrelationExtensive(t *testing.T) {
	// Basic cases that are verified to pass
	s1 := []float64{1, 2, 3, 4, 5}
	s2 := []float64{}

	// Test with ascending series
	a, err := stats.AutoCorrelation(s1, 1)
	if err != nil {
		t.Errorf("Should not have returned an error")
	}
	if !almostEqual(a, 0.4) {
		t.Errorf("Expected result 0.4, but got %f", a)
	}

	// Test with empty input
	_, err = stats.AutoCorrelation(s2, 1)
	if err != stats.EmptyInputErr {
		t.Errorf("Should have returned empty input error")
	}

	// Test with descending series
	s3 := []float64{5.0, 4.0, 3.0, 2.0, 1.0}
	a, err = stats.AutoCorrelation(s3, 1)
	if err != nil {
		t.Errorf("Should not have returned an error")
	}
	if !almostEqual(a, 0.4) {
		t.Errorf("Expected result 0.4, but got %f", a)
	}
}

// Helper function to compare float values with some tolerance
func almostEqual(a, b float64) bool {
	if (a == 0 && b == 0) || (a == b) {
		return true
	}
	diff := a - b
	if diff < 0 {
		diff = -diff
	}
	relative := diff
	if b != 0 {
		relative = diff / b
	}
	return relative < 0.000001
}

