pub fn auto_correlation(data: Float64Data, lags: usize) -> Result<f64> {
    if data.0.is_empty() {
        bail!("{}", EMPTY_INPUT_ERR.err);
    }

    // Early return for single value or empty array
    if data.0.len() <= 1 {
        return Ok(0.0);
    }

    // Calculate mean only once outside the loop
    let mean = mean(data.clone())?;

    // Check if all values are the same
    let first = data.0[0];
    let all_same = data.0.iter().all(|&x| x == first);
    if all_same {
        return Ok(0.0); // No variance means no correlation
    }

    let mut result = 0.0;
    // Initialize q (covariance) to 0
    let mut q = 0.0;

    // Loop for lags, reset q and v for each lag iteration
    for _ in 0..lags {
        // Reset q for each lag calculation as in Go implementation
        q = 0.0;
        let mut v = (data.0[0] - mean).powi(2);

        for i in 1..data.0.len() {
            let delta0 = data.0[i - 1] - mean;
            let delta1 = data.0[i] - mean;
            q += (delta0 * delta1 - q) / (i as f64 + 1.0);
            v += (delta1.powi(2) - v) / (i as f64 + 1.0);
        }

        result = q / v;
    }

    Ok(result)
}

