package stats_test

import (
	"math"
	"testing"

	"github.com/montanaflynn/stats"
)

func TestChebyshevDistanceComprehensive(t *testing.T) {
	testCases := []struct {
		name       string
		dataPointX []float64
		dataPointY []float64
		expected   float64
		shouldErr  bool
	}{
		{
			name:       "Standard case - different vectors",
			dataPointX: []float64{2, 3, 4, 5, 6, 7, 8},
			dataPointY: []float64{8, 7, 6, 5, 4, 3, 2},
			expected:   6.0,
			shouldErr:  false,
		},
		{
			name:       "Equal vectors",
			dataPointX: []float64{1, 2, 3, 4, 5},
			dataPointY: []float64{1, 2, 3, 4, 5},
			expected:   0.0,
			shouldErr:  false,
		},
		{
			name:       "Negative numbers",
			dataPointX: []float64{-1, -2, -3, -4, -5},
			dataPointY: []float64{5, 4, 3, 2, 1},
			expected:   6.0,
			shouldErr:  false,
		},
		{
			name:       "Mixed positive and negative",
			dataPointX: []float64{-5, -4, 0, 4, 5},
			dataPointY: []float64{5, 4, 0, -4, -5},
			expected:   10.0,
			shouldErr:  false,
		},
		{
			name:       "Single element",
			dataPointX: []float64{10},
			dataPointY: []float64{5},
			expected:   5.0,
			shouldErr:  false,
		},
		{
			name:       "Empty slices",
			dataPointX: []float64{},
			dataPointY: []float64{},
			expected:   math.NaN(),
			shouldErr:  true,
		},
		{
			name:       "Different length slices",
			dataPointX: []float64{1, 2, 3},
			dataPointY: []float64{1, 2},
			expected:   math.NaN(),
			shouldErr:  true,
		},
		{
			name:       "Different length slices - reversed",
			dataPointX: []float64{1, 2},
			dataPointY: []float64{1, 2, 3},
			expected:   math.NaN(),
			shouldErr:  true,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			result, err := stats.ChebyshevDistance(tc.dataPointX, tc.dataPointY)

			// Check error cases
			if tc.shouldErr {
				if err == nil {
					t.Errorf("Expected an error, but got none")
				}
				if !math.IsNaN(result) {
					t.Errorf("Expected NaN result for error case, got: %v", result)
				}
				return
			}

			// No error expected but got one
			if err != nil {
				t.Errorf("Unexpected error: %v", err)
				return
			}

			// Check result value
			if math.Abs(result-tc.expected) > 1e-10 {
				t.Errorf("Expected distance: %v, got: %v", tc.expected, result)
			}
		})
	}
}

