import (
	"math"
	"testing"

	"github.com/montanaflynn/stats"
)

func TestVarianceEquivalence(t *testing.T) {
	// Test with population variance (sample = 0)
	testCases := []struct {
		name     string
		input    []float64
		sample   int
		expected float64
		err      error
	}{
		{"Normal case", []float64{1, 2, 3, 4, 5}, 0, 2.0, nil},
		{"Empty input", []float64{}, 0, math.NaN(), stats.EmptyInputErr},
		{"Single value", []float64{1}, 0, 0, nil},
		{"Same values", []float64{3, 3, 3, 3}, 0, 0, nil},
		{"Negative values", []float64{-1, -2, -3, -4, -5}, 0, 2.0, nil},
		{"Mixed values", []float64{-10, 0, 10, 20}, 0, 125.0, nil},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			// Use PopulationVariance since _variance is not exported
			var result float64
			var err error

			if len(tc.input) > 0 {
				if tc.sample == 0 {
					result, err = stats.PopulationVariance(tc.input)
				} else {
					result, err = stats.SampleVariance(tc.input)
				}
			} else {
				// For empty input, we need to check the error directly
				_, err = stats.PopulationVariance(tc.input)
				result = math.NaN()
			}

			// Check error
			if tc.err != nil && err != tc.err {
				t.Errorf("Expected error: %v, got: %v", tc.err, err)
			} else if tc.err == nil && err != nil {
				t.Errorf("Unexpected error: %v", err)
			}

			// Check result
			if tc.err == nil && len(tc.input) > 0 {
				if math.IsNaN(tc.expected) && !math.IsNaN(result) {
					t.Errorf("Expected NaN, got: %v", result)
				} else if !math.IsNaN(tc.expected) && math.Abs(result-tc.expected) > 1e-6 {
					t.Errorf("Expected: %v, got: %v", tc.expected, result)
				}
			}
		})
	}

	// Test with sample variance (sample = 1)
	sampleTestCases := []struct {
		name     string
		input    []float64
		sample   int
		expected float64
		err      error
	}{
		{"Normal case", []float64{1, 2, 3, 4, 5}, 1, 2.5, nil},
		{"Empty input", []float64{}, 1, math.NaN(), stats.EmptyInputErr},
		{"Single value", []float64{1}, 1, math.Inf(1), nil}, // Division by 0
		{"Same values", []float64{3, 3, 3, 3}, 1, 0, nil},
		{"Negative values", []float64{-1, -2, -3, -4, -5}, 1, 2.5, nil},
		{"Mixed values", []float64{-10, 0, 10, 20}, 1, 166.66666666666666, nil},
	}

	for _, tc := range sampleTestCases {
		t.Run(tc.name+" (sample)", func(t *testing.T) {
