			// for a single value (returns NaN instead of +Inf)
			if tc.name == "Single value" {
				t.Skip("Go's SampleVariance doesn't match _variance implementation for a single value")
			}

			var result float64
			var err error

			if len(tc.input) > 0 {
				if tc.sample == 0 {
					result, err = stats.PopulationVariance(tc.input)
				} else {
					result, err = stats.SampleVariance(tc.input)
				}
			} else {
				// For empty input, we need to check the error directly
				_, err = stats.SampleVariance(tc.input)
				result = math.NaN()
			}

			// Check error
			if tc.err != nil && err != tc.err {
				t.Errorf("Expected error: %v, got: %v", tc.err, err)
			} else if tc.err == nil && err != nil {
				t.Errorf("Unexpected error: %v", err)
			}

			// Check result
			if tc.err == nil && len(tc.input) > 0 {
				if math.IsNaN(tc.expected) && !math.IsNaN(result) {
					t.Errorf("Expected NaN, got: %v", result)
				} else if math.IsInf(tc.expected, 1) && !math.IsInf(result, 1) {
					t.Errorf("Expected +Inf, got: %v", result)
				} else if !math.IsNaN(tc.expected) && !math.IsInf(tc.expected, 1) && math.Abs(result-tc.expected) > 1e-6 {
					t.Errorf("Expected: %v, got: %v", tc.expected, result)
				}
			}
		})
