package stats_test

import (
	"math"
	"testing"

	"github.com/montanaflynn/stats"
)

func TestPopulationVarianceImplementation(t *testing.T) {
	// Test with empty dataset - should return NaN and EmptyInputErr
	empty := []float64{}
	e, err := stats.PopulationVariance(empty)
	if !math.IsNaN(e) {
		t.Errorf("Expected NaN for empty input, got %v", e)
	}
	if err != stats.EmptyInputErr {
		t.Errorf("Expected EmptyInputErr for empty input, got %v", err)
	}

	// Test with normal data set
	data := []float64{1, 2, 3, 4, 5}
	expected := 2.0
	result, err := stats.PopulationVariance(data)
	if err != nil {
		t.Errorf("Unexpected error: %v", err)
	}
	if result != expected {
		t.Errorf("Expected %v, but got %v", expected, result)
	}

	// Test with single value - should return 0 (no variance)
	single := []float64{1}
	singleResult, err := stats.PopulationVariance(single)
	if err != nil {
		t.Errorf("Unexpected error: %v", err)
	}
	if singleResult != 0.0 {
		t.Errorf("Expected 0.0 for single value, got %v", singleResult)
	}

	// Test with negative values - should still work fine
	negatives := []float64{-1, -2, -3, -4, -5}
	negResult, err := stats.PopulationVariance(negatives)
	if err != nil {
		t.Errorf("Unexpected error: %v", err)
	}
	if negResult != expected {
		t.Errorf("Expected %v, but got %v", expected, negResult)
	}

	// Test with mixed positive and negative values
	mixed := []float64{-2, -1, 0, 1, 2}
	mixedResult, err := stats.PopulationVariance(mixed)
	if err != nil {
		t.Errorf("Unexpected error: %v", err)
	}
	if mixedResult != expected {
		t.Errorf("Expected %v, but got %v", expected, mixedResult)
	}
}

