				t.Errorf("Correlation() error = %v, wantErr %v", err, tc.wantErr)
				return
			}

			// Check for NaN cases
			if tc.wantErr && err != nil {
				if !math.IsNaN(got) {
					t.Errorf("Correlation() got = %v, want NaN when error occurs", got)
				}
				return
			}

			// For very small values, check if they're close enough
			if !closeEnough(got, tc.want, 1e-10) {
				t.Errorf("Correlation() got = %v, want %v", got, tc.want)
			}
		})
	}
}

// Helper function to compare floating point values
func closeEnough(a, b, tolerance float64) bool {
	if math.IsNaN(a) && math.IsNaN(b) {
		return true
	}
	return math.Abs(a-b) <= tolerance
}

