fn test_max_equivalence() {
    // Test cases for the max function
    let test_cases = [
        // Normal case with positive numbers
        (
            vec![1.0, 3.5, 2.0, 4.7, 3.0],
            Ok(4.7),
            "Normal case with positive numbers",
        ),
        // Normal case with negative numbers
        (
            vec![-10.0, -5.5, -3.2, -7.8],
            Ok(-3.2),
            "Normal case with negative numbers",
        ),
        // Mixed positive and negative numbers
        (
            vec![-5.0, 2.5, 0.0, -3.0, 1.8],
            Ok(2.5),
            "Mixed positive and negative numbers",
        ),
        // Single element array
        (vec![42.0], Ok(42.0), "Single element array"),
        // With Infinity values
        (vec![1.0, std::f64::INFINITY, 5.0, 2.0], Ok(std::f64::INFINITY), "With Infinity values"),
        // Empty array - should return error
        (vec![], Err(String::from("Empty input")), "Empty array"),
    ];

    for (input, expected, name) in test_cases.iter() {
        let data = crate::data::Float64Data(input.clone());
        let result = max(data);

        match (result, expected) {
            (Ok(val), Ok(exp_val)) => {
                // Special handling for infinity cases
                if exp_val.is_infinite() {
                    assert!(
                        val.is_infinite() && val.is_sign_positive() == exp_val.is_sign_positive(),
                        "{}: Expected {}, got {}",
                        name,
                        exp_val,
                        val
                    );
                } else {
                    assert_eq!(val, *exp_val, "{}: Expected {}, got {}", name, exp_val, val);
                }
            }
            (Err(_), Err(_)) => {
                // Both returned errors as expected
                // We don't need to check the exact error message
            }
            (Ok(val), Err(_)) => {
                panic!("{}: Expected error but got value: {}", name, val);
            }
            (Err(err), Ok(exp_val)) => {
                panic!("{}: Expected {}, but got error: {}", name, exp_val, err);
            }
        }
    }
}

