                49.5,
                false,
                None,
            ),
        ];

        for (name, input_vec, percent, expected, expect_error, error_type) in test_cases {
            // Create a copy of the original input to test side effects
            let original = input_vec.clone();
            let input = Float64Data(input_vec);

            // Test the percentile function
            let result = percentile(input.clone(), percent);

            // Check error behavior
            if expect_error {
                assert!(
                    result.is_err(),
                    "{}: Expected error, got {:?}",
                    name,
                    result
                );

                // If we expected a specific error type, verify it
                if let Some(err_type) = error_type {
                    match err_type {
                        "EMPTY_INPUT_ERR" => {
                            let err = result.unwrap_err().to_string();
                            assert_eq!(
                                err,
                                EMPTY_INPUT_ERR.to_string(),
                                "{}: Expected EMPTY_INPUT_ERR, got {}",
                                name,
                                err
                            );
                        }
                        "BOUNDS_ERR" => {
                            let err = result.unwrap_err().to_string();
                            assert_eq!(
                                err,
                                BOUNDS_ERR.to_string(),
                                "{}: Expected BOUNDS_ERR, got {}",
                                name,
                                err
                            );
                        }
                        _ => panic!("Unknown error type: {}", err_type),
                    }
                }
            } else {
                assert!(
                    result.is_ok(),
                    "{}: Did not expect error, got {:?}",
                    name,
                    result
                );

                // Check the result value
                let got = result.unwrap();
                if expected.is_nan() {
                    assert!(
                        got.is_nan(),
                        "{}: Expected NaN, got {}",
                        name,
                        got
                    );
                } else {
                    assert_eq!(
                        got, expected,
                        "{}: Expected {}, got {}",
                        name, expected, got
                    );
                }
            }

            // Verify that original input was not modified (no side effects)
            assert_eq!(
                input.0, original,
                "{}: Function modified input",
                name
            );
        }
    }
}

