			percent:     -1,
			expectedErr: stats.BoundsErr,
		},
		{
			name:        "Percent greater than 100",
			input:       []float64{1, 2, 3},
			percent:     101,
			expectedErr: stats.BoundsErr,
		},
		{
			name:        "Edge case: percent = 100",
			input:       []float64{1, 2, 3, 4, 5},
			percent:     100,
			expected:    5,
			expectedErr: nil,
		},
		{
			name:        "Edge case: percent = 0",
			input:       []float64{1, 2, 3, 4, 5},
			percent:     0,
			expected:    1,
			expectedErr: nil,
		},
		{
			name:        "Unsorted input",
			input:       []float64{5, 3, 1, 4, 2},
			percent:     50,
			expected:    3,
			expectedErr: nil,
		},
