			// Check error
			if tc.expectedErr != nil {
				if err == nil {
					t.Errorf("Expected error %v but got nil", tc.expectedErr)
				} else if err != tc.expectedErr {
					t.Errorf("Expected error %v but got %v", tc.expectedErr, err)
				}
				return
			}

			// Check no error when not expected
			if err != nil {
