package stats_test

import (
	"math"
	"testing"

	"github.com/montanaflynn/stats"
)

func TestStandardDeviationEquivalence(t *testing.T) {
	testCases := []struct {
		data     []float64
		expected float64
		name     string
	}{
		{
			name:     "Standard case with positive numbers",
			data:     []float64{1, 2, 3, 4, 5},
			expected: math.Sqrt(2),
		},
		{
			name:     "Standard case with negative numbers",
			data:     []float64{-1, -2, -3, -4, -5},
			expected: math.Sqrt(2),
		},
		{
			name:     "Mixed positive and negative numbers",
			data:     []float64{-2, -1, 0, 1, 2},
			expected: math.Sqrt(2),
		},
		{
			name:     "Single element",
			data:     []float64{5},
			expected: 0,
		},
		{
			name:     "Empty slice",
			data:     []float64{},
			expected: math.NaN(),
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			// Test StandardDeviation function
			sd, err := stats.StandardDeviation(tc.data)

			if len(tc.data) == 0 {
				if err == nil {
					t.Errorf("Expected error for empty data but got nil")
				}
				if !math.IsNaN(sd) {
					t.Errorf("Expected NaN for empty data but got %v", sd)
				}
			} else {
				if err != nil {
					t.Errorf("StandardDeviation returned an unexpected error: %v", err)
				}

				// Use approximate comparison for floating point
				if !almostEqual(sd, tc.expected, 0.0001) {
					t.Errorf("StandardDeviation(%v) = %v, expected %v", tc.data, sd, tc.expected)
				}

				// Verify that StandardDeviation matches StandardDeviationPopulation
				sdPop, err := stats.StandardDeviationPopulation(tc.data)
				if err != nil {
					t.Errorf("StandardDeviationPopulation returned an unexpected error: %v", err)
				}

				if sd != sdPop {
					t.Errorf("StandardDeviation and StandardDeviationPopulation returned different values: %v vs %v", sd, sdPop)
				}
			}
		})
	}
}

// Helper function for float comparison
func almostEqual(a, b, tolerance float64) bool {
	if math.IsNaN(a) && math.IsNaN(b) {
		return true
	}
	return math.Abs(a-b) <= tolerance
}

