func TestDescribePercentileFuncWithNaN(t *testing.T) {
	// This test verifies that when allow_nan is true and percentile function returns an error,
	// the percentile is still added to the description

	data := []float64{1.0, 2.0, 3.0}
	percentiles := []float64{25.0, 50.0, 75.0}

	// Define a percentile function that returns an error for 25th percentile
	percentileFunc := func(input stats.Float64Data, percentile float64) (float64, error) {
		if percentile == 25.0 {
			return math.NaN(), stats.ErrNaN
		}
		return stats.Percentile(input, percentile)
	}

	desc, err := stats.DescribePercentileFunc(data, true, &percentiles, percentileFunc)

	// Should not return an error since allow_nan is true
	if err != nil {
		t.Errorf("Expected no error with allow_nan=true, got: %v", err)
	}

	// Should include all three percentiles in the result
	if len(desc.DescriptionPercentiles) != 3 {
		t.Errorf("Expected 3 percentiles in result, got %d", len(desc.DescriptionPercentiles))
	}

	// The 25th percentile value should be NaN
	found := false
	for _, p := range desc.DescriptionPercentiles {
		if p.Percentile == 25.0 {
			found = true
			if !math.IsNaN(p.Value) {
				t.Errorf("Expected NaN value for 25th percentile, got %f", p.Value)
			}
		}
	}

	if !found {
		t.Errorf("25th percentile not found in results")
	}
}

func TestDescribePercentileFuncWithoutNaN(t *testing.T) {
