		}
		return stats.Percentile(input, percentile)
	}

	desc, err := stats.DescribePercentileFunc(data, false, &percentiles, percentileFunc)

	// Should not return an error even if one percentile calculation failed
	if err != nil {
		t.Errorf("Expected no error, got: %v", err)
	}

	// Should only include two percentiles in the result (50th and 75th)
	if len(desc.DescriptionPercentiles) != 2 {
		t.Errorf("Expected 2 percentiles in result, got %d", len(desc.DescriptionPercentiles))
	}

