func TestNormalize(t *testing.T) {
	// Access the normalize function through reflection since it's private
	normalizeFunc := reflect.ValueOf(stats.Entropy).Call([]reflect.Value{
		reflect.ValueOf(stats.Float64Data{1, 2, 3}),
	})[1].Interface()
	if normalizeFunc != nil {
		t.Skip("normalize function is private and cannot be directly tested")
		return
	}

	// Testing through the side effect on the input data
	testCases := []struct {
		name     string
		input    stats.Float64Data
		expected stats.Float64Data
	}{
		{
			name:     "basic normalization",
			input:    stats.Float64Data{1.0, 2.0, 3.0},
			expected: stats.Float64Data{1.0/6.0, 2.0/6.0, 3.0/6.0},
		},
		{
			name:     "already normalized",
			input:    stats.Float64Data{0.2, 0.3, 0.5},
			expected: stats.Float64Data{0.2, 0.3, 0.5},
		},
		{
			name:     "zeros and negatives",
			input:    stats.Float64Data{0.0, 1.0, -1.0},
			expected: stats.Float64Data{0.0, 1.0, -1.0},
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			// Make a copy to check if the original is modified
			original := make(stats.Float64Data, len(tc.input))
			copy(original, tc.input)

			// Call Entropy which uses normalize internally
			stats.Entropy(tc.input)

			// Now tc.input should be modified if normalize modifies in place
			// Compare with original to see if it was modified
			if !reflect.DeepEqual(tc.input, original) {
				t.Logf("Input was modified, which indicates normalize modifies in place")

				// This is just to help us observe the behavior, not an actual test assertion
				for i := range tc.input {
					if tc.input[i] != original[i] {
						t.Logf("Input[%d] changed from %.6f to %.6f", i, original[i], tc.input[i])
					}
				}
			} else {
				t.Logf("Input was not modified, which indicates normalize returns a new copy")
			}
		})
	}
}

