pub(crate) fn normalize(mut input: Float64Data) -> Result<Float64Data> {
    let sum = input.sum()?;
    // Modify input in-place (matching Go implementation)
    for i in 0..input.0.len() {
        input.0[i] = input.0[i] / sum;
    }
    Ok(input)
}

