#[cfg(not(feature = "mock"))]
pub fn entropy(input: Float64Data) -> Result<f64> {
    // Check for all zeros case
    let mut all_zeros = true;
    let mut has_negative = false;

    for i in 0..input.len() {
        let v = input.get(i);
        if v != 0.0 {
            all_zeros = false;
        }
        if v < 0.0 {
            has_negative = true;
        }
    }

    // If all values are zero, return an error like the Go implementation
    if all_zeros && input.len() > 0 {
        return Err(anyhow!("Input must not be all zeros"));
    }

    // If there are negative values, return an error like the Go implementation
    if has_negative {
        return Err(anyhow!("Input must not contain negative values"));
    }

    let input = normalize(input)?;
    let mut result = 0.0;
    for i in 0..input.len() {
        let v = input.get(i);
        if v != 0.0 {
            result += v * v.ln();
        }
    }
    Ok(-result)
}

