// Helper function for floating point comparison
func closeEnough(a, b, tolerance float64) bool {
	if a == b {
		return true
	}
	diff := math.Abs(a - b)
	if b != 0 {
		return diff < math.Abs(tolerance*b)
	}
	return diff < tolerance
}

