			input:   []float64{2, 0, 3, 4},
			want:    1.86,
			wantErr: false,
		},
		{
			name:    "Input with zero at end",
			input:   []float64{2, 3, 4, 0},
			want:    0,
			wantErr: false,
		},
		{
			name:    "Input with all zeros",
			input:   []float64{0, 0, 0},
			want:    0,
			wantErr: false,
		},
		{
			name:    "Regular input without zeros",
			input:   []float64{2, 8, 32},
			want:    8,
			wantErr: false,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			got, err := stats.GeometricMean(tc.input)

			// Check error cases
			if tc.wantErr && err == nil {
				t.Errorf("GeometricMean() expected error for input %v but got none", tc.input)
			}
