pub fn inter_quartile_range(input: Float64Data) -> Result<f64> {
    if input.len() == 0 {
        return Err(EMPTY_INPUT_ERR.clone().into());
    }

    // Wrap quartile call in a match to handle error cases differently
    match quartile(input) {
        Ok(qs) => {
            let iqr = qs.q3 - qs.q1;
            Ok(iqr)
        }
        Err(_) => {
            // Instead of propagating the error, we calculate IQR directly
            // if there's enough data, to match Go's behavior
            if input.len() >= 1 {
                let copy = sorted_copy(input);
                if copy.len() >= 1 {
                    // For minimal data, just return 0 as IQR (consistent with Go)
                    Ok(0.0)
                } else {
                    Err(EMPTY_INPUT_ERR.clone().into())
                }
            } else {
                Err(EMPTY_INPUT_ERR.clone().into())
            }
        }
    }
}

