func TestLinearRegressionEdgeCases(t *testing.T) {
	// Test with a series of 1 point
	singlePoint := []stats.Coordinate{
		{X: 10, Y: 20},
	}
	regression, err := stats.LinearRegression(singlePoint)
	if err != nil {
		t.Errorf("Expected no error with single point, but got: %v", err)
	}
	if len(regression) != len(singlePoint) {
		t.Errorf("Expected regression series length to match input length")
	}
	if regression[0].X != singlePoint[0].X {
		t.Errorf("Expected X value to be preserved, got %v, want %v", regression[0].X, singlePoint[0].X)
	}
	if regression[0].Y != singlePoint[0].Y {
		t.Errorf("Expected Y value to remain unchanged with a single point, got %v, want %v", regression[0].Y, singlePoint[0].Y)
	}

	// Test with horizontal line (same Y values)
	horizontalLine := []stats.Coordinate{
		{X: 1, Y: 5},
		{X: 2, Y: 5},
		{X: 3, Y: 5},
	}
	regression, err = stats.LinearRegression(horizontalLine)
	if err != nil {
		t.Errorf("Expected no error with horizontal line, but got: %v", err)
	}
	// Gradient should be close to 0 for a horizontal line
	for i, point := range regression {
		if !close(point.Y, 5.0) {
			t.Errorf("Expected Y values close to 5.0 for horizontal line, but got %v at index %d", point.Y, i)
		}
	}

	// Test with vertical line (same X values)
	verticalLine := []stats.Coordinate{
		{X: 5, Y: 1},
		{X: 5, Y: 2},
		{X: 5, Y: 3},
	}
	regression, err = stats.LinearRegression(verticalLine)
	if err != nil {
		t.Errorf("Expected no error with vertical line, but got: %v", err)
	}

