// Helper function to check if two float values are close enough
func closeEnough(a, b, epsilon float64) bool {
	if a == b {
		return true
	}
	diff := math.Abs(a - b)
	if b == 0 {
		return diff < epsilon
	}
	return diff/math.Abs(b) < epsilon
}

