package stats_test

import (
	"testing"

	"github.com/montanaflynn/stats"
)

func TestManhattanDistance(t *testing.T) {
	// Test cases
	testCases := []struct {
		name      string
		dataX     []float64
		dataY     []float64
		expected  float64
		expectErr bool
	}{
		{
			name:      "Basic case with positive numbers",
			dataX:     []float64{2, 3, 4, 5},
			dataY:     []float64{1, 2, 3, 4},
			expected:  4.0,
			expectErr: false,
		},
		{
			name:      "Mixed positive and negative numbers",
			dataX:     []float64{-2, 3, -4, 5},
			dataY:     []float64{1, -2, 3, -4},
			expected:  24.0,
			expectErr: false,
		},
		{
			name:      "Empty slices",
			dataX:     []float64{},
			dataY:     []float64{},
			expected:  0,
			expectErr: true,
		},
		{
			name:      "Different length slices",
			dataX:     []float64{1, 2, 3},
			dataY:     []float64{1, 2},
			expected:  0,
			expectErr: true,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			result, err := stats.ManhattanDistance(tc.dataX, tc.dataY)

			// Check error expectation
			if tc.expectErr && err == nil {
				t.Errorf("Expected error, but got nil")
			}
			if !tc.expectErr && err != nil {
				t.Errorf("Expected no error, but got: %v", err)
			}

			// If no error expected, check the result
			if !tc.expectErr {
				if result != tc.expected {
					t.Errorf("Expected %f, but got %f", tc.expected, result)
				}
			}
		})
	}
