		{"exact_half_negative_rounds_up", -3.145, 2, -3.15, false},
		{"zero_places_positive", 3.75, 0, 4.0, false},
		{"zero_places_negative", -3.75, 0, -4.0, false},
		{"large_positive_places", 3.14159, 10, 3.14159, false},
		{"negative_large_number", -9999.9999, 2, -10000.00, false},
		{"small_positive_number", 0.0000123, 7, 0.0000123, false},
		{"small_negative_number", -0.0000123, 7, -0.0000123, false},
		{"infinity_positive", math.Inf(1), 2, math.Inf(1), false},
		{"infinity_negative", math.Inf(-1), 2, math.Inf(-1), false},
		{"nan_input", math.NaN(), 2, math.NaN(), true},
		{"negative_places", 3.14159, -2, 0.0, false},  // Should round to nearest hundred
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			result, err := stats.Round(tc.input, tc.places)

			// Check error handling
			if tc.isError {
				if err == nil {
					t.Errorf("Expected error but got none")
				}
			} else {
				if err != nil {
					t.Errorf("Unexpected error: %v", err)
				} else if math.IsNaN(tc.expected) {
					if !math.IsNaN(result) {
						t.Errorf("Expected NaN but got %v", result)
					}
				} else if math.IsInf(tc.expected, 1) {
					if !math.IsInf(result, 1) {
						t.Errorf("Expected +Inf but got %v", result)
					}
				} else if math.IsInf(tc.expected, -1) {
					if !math.IsInf(result, -1) {
						t.Errorf("Expected -Inf but got %v", result)
					}
				} else if result != tc.expected {
					t.Errorf("Round(%v, %d) = %v; want %v", tc.input, tc.places, result, tc.expected)
				}
			}
		})
	}
}

