package stats_test

import (
	"math"
	"testing"

	"github.com/montanaflynn/stats"
)

func TestSigmoidEquivalence(t *testing.T) {
	tests := []struct {
		name     string
		input    []float64
		expected []float64
		wantErr  bool
	}{
		{
			name:     "Empty input",
			input:    []float64{},
			expected: nil,
			wantErr:  true,
		},
		{
			name:     "Single positive value",
			input:    []float64{2.0},
			expected: []float64{0.8807970779778823},
			wantErr:  false,
		},
		{
			name:     "Single negative value",
			input:    []float64{-2.0},
			expected: []float64{0.11920292202211755},
			wantErr:  false,
		},
		{
			name:     "Zero value",
			input:    []float64{0.0},
			expected: []float64{0.5},
			wantErr:  false,
		},
		{
			name:     "Multiple values",
			input:    []float64{-3.0, -1.0, 0.0, 1.0, 3.0},
			expected: []float64{0.04742587317756678, 0.2689414213699951, 0.5, 0.7310585786300049, 0.9525741268224331},
			wantErr:  false,
		},
		{
			name:     "Large positive value",
			input:    []float64{10.0},
			expected: []float64{0.9999546021312976},
			wantErr:  false,
		},
		{
			name:     "Large negative value",
			input:    []float64{-10.0},
			expected: []float64{0.00004539786870243441},
			wantErr:  false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got, err := stats.Sigmoid(tt.input)
			if (err != nil) != tt.wantErr {
				t.Errorf("Sigmoid() error = %v, wantErr %v", err, tt.wantErr)
				return
			}

			if tt.wantErr {
				if err != stats.EmptyInputErr {
					t.Errorf("Sigmoid() expected EmptyInputErr, got %v", err)
				}
				return
			}

			if len(got) != len(tt.expected) {
				t.Errorf("Sigmoid() got length = %v, expected length %v", len(got), len(tt.expected))
				return
			}

			for i := range got {
				if math.Abs(got[i]-tt.expected[i]) > 1e-15 {
					t.Errorf("Sigmoid()[%d] = %v, expected %v", i, got[i], tt.expected[i])
				}
			}
		})
	}
}

