func TestSoftMaxEquivalenceNormal(t *testing.T) {
	testCases := [][]float64{
		{3.0, 1.0, 0.2},
		{0.0, 0.0, 0.0},
		{-1.0, -2.0, -3.0},
		{1000.0, 1000.1, 999.9},
		{-1000.0, -1000.1, -999.9},
		{1.0},
	}

	for _, tc := range testCases {
		sm, err := stats.SoftMax(tc)
		if err != nil {
			t.Errorf("Error calculating softmax for %v: %v", tc, err)
			continue
		}

		// Check that the softmax values sum to 1
		sum := 0.0
		for _, v := range sm {
			sum += v
		}

		if sum < 0.9999 || sum > 1.0001 {
			t.Errorf("Softmax values for %v do not sum to 1. Sum: %v", tc, sum)
		}

		// Check that all values are between 0 and 1
		for i, v := range sm {
			if v < 0.0 || v > 1.0 {
				t.Errorf("Softmax value %v at index %d for input %v is outside [0,1] range", v, i, tc)
			}
		}
	}
}

