	// Test with large values that would cause overflow without the max subtraction
	input := []float64{1000.0, 999.0, 998.0}
	sm, err := stats.SoftMax(input)
	if err != nil {
		t.Errorf("Error calculating softmax for large values: %v", err)
		return
	}

	// First value should be largest
	if sm[0] <= sm[1] || sm[0] <= sm[2] {
		t.Errorf("Expected first value to be largest, got %v", sm)
	}

	// Sum should be close to 1
	sum := 0.0
	for _, v := range sm {
		sum += v
	}

	if sum < 0.9999 || sum > 1.0001 {
		t.Errorf("Softmax values for large values do not sum to 1. Sum: %v", sum)
	}
}

