pub fn soft_max(input: Float64Data) -> Result<Vec<f64>> {
    if input.len() == 0 {
        bail!(EMPTY_INPUT.err.clone());
    }

    let c = max(input.clone())?.to_owned();
    let s: f64 = input
        .0
        .iter()
        .map(|x| (x - c).exp())
        .sum();

    let sm: Vec<f64> = input
        .0
        .iter()
        .map(|x| (x - c).exp() / s)
        .collect();

    Ok(sm)
}

