pub fn standard_deviation_sample(input: Float64Data) -> Result<f64, anyhow::Error> {
    if input.len() == 0 {
        return Err(anyhow!("Input data is empty"));
    }

    let variance = sample_variance(input)?;
    let std_dev = variance.sqrt();

    Ok(std_dev)
}

