func TestTrimeanWithVariousInputs(t *testing.T) {
	testCases := []struct {
		name     string
		data     []float64
		expected float64
		hasError bool
	}{
		{"Empty slice", []float64{}, 0, true},
		{"Single value", []float64{5}, 5, false},
		{"Two values", []float64{1, 3}, 2, false},
		{"Three values", []float64{1, 3, 5}, 3, false},
		{"Four values", []float64{1, 3, 5, 7}, 4, false},
		{"Multiple identical values", []float64{5, 5, 5, 5, 5}, 5, false},
		{"Normal distribution", []float64{1, 3, 4, 4, 6, 6, 6, 6, 7, 7, 7, 8, 8, 9, 9, 10, 11, 12, 13}, 7.25, false},
		{"Negative values", []float64{-10, -7, -4, -1, 0, 3, 6, 9}, -0.5, false},
		{"Unsorted data", []float64{9, 1, 5, 7, 3}, 5, false},
		{"Large values", []float64{1000, 2000, 3000, 4000, 5000}, 3000, false},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			result, err := stats.Trimean(tc.data)

			// Check error handling
			if tc.hasError {
				if err == nil {
					t.Errorf("Expected an error for input %v, but got none", tc.data)
				}
				// If we expect an error, we're done with this test case
				return
			}

			// If we don't expect an error, we should check there isn't one
			if err != nil {
				t.Errorf("Unexpected error for input %v: %v", tc.data, err)
				return
			}

			// Check the result with a small epsilon for floating point comparison
			if math.Abs(result-tc.expected) > 1e-10 {
				t.Errorf("For input %v: expected %v, got %v", tc.data, tc.expected, result)
			}
		})
	}
}

func TestTrimeanFormula(t *testing.T) {
	// Test specifically that the trimean formula is correctly implemented as (Q1 + 2*Q2 + Q3)/4
	data := []float64{1, 2, 3, 4, 5, 6, 7, 8, 9}

	// Calculate quartiles manually to verify the formula
	q, err := stats.Quartile(data)
	if err != nil {
		t.Fatalf("Failed to calculate quartiles: %v", err)
	}

	// Calculate expected trimean using the formula
	expected := (q.Q1 + 2*q.Q2 + q.Q3) / 4

	// Get the actual result
	result, err := stats.Trimean(data)
	if err != nil {
		t.Fatalf("Unexpected error: %v", err)
	}

	// Compare with a small epsilon for floating point comparison
	if math.Abs(result-expected) > 1e-10 {
		t.Errorf("Trimean formula not correctly implemented: expected %v, got %v", expected, result)
	}
}

